import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused Conv-BN-Scale CUDA kernel
conv_bn_scale_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

template<typename scalar_t>
__global__ void conv_bn_scale_kernel(
    const scalar_t* __restrict__ input,
    const scalar_t* __restrict__ weight,
    const scalar_t* __restrict__ bias,
    const scalar_t* __restrict__ running_mean,
    const scalar_t* __restrict__ running_var,
    scalar_t* __restrict__ output,
    const float eps,
    const float scaling_factor,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int height,
    const int width,
    const int kernel_size,
    const int output_h,
    const int output_w,
    const int padding
) {
    // Each thread handles one output element
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    const int total_output_elements = batch_size * out_channels * output_h * output_w;

    if (idx >= total_output_elements) return;

    // Decompose index
    const int n = idx / (out_channels * output_h * output_w);
    const int c = (idx / (output_h * output_w)) % out_channels;
    const int h = (idx / output_w) % output_h;
    const int w = idx % output_w;

    scalar_t result = 0;

    // Perform convolution with padding
    for (int ic = 0; ic < in_channels; ++ic) {
        for (int kh = 0; kh < kernel_size; ++kh) {
            for (int kw = 0; kw < kernel_size; ++kw) {
                const int h_in = h + kh - padding;
                const int w_in = w + kw - padding;

                if (h_in >= 0 && h_in < height && w_in >= 0 && w_in < width) {
                    const int input_idx = ((n * in_channels + ic) * height + h_in) * width + w_in;
                    const int weight_idx = ((c * in_channels + ic) * kernel_size + kh) * kernel_size + kw;

                    result += input[input_idx] * weight[weight_idx];
                }
            }
        }
    }

    // Add bias
    if (bias != nullptr) {
        result += bias[c];
    }

    // Apply Batch Normalization with scaling
    const scalar_t mean = running_mean[c];
    const scalar_t var = running_var[c];
    const scalar_t inv_std = 1.0 / sqrt(var + eps);
    result = (result - mean) * inv_std * scaling_factor;

    // Store result
    output[idx] = result;
}

torch::Tensor conv_bn_scale_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    torch::Tensor running_mean,
    torch::Tensor running_var,
    float eps,
    float scaling_factor,
    int padding
) {
    // Get tensor dimensions
    const int batch_size = input.size(0);
    const int in_channels = input.size(1);
    const int height = input.size(2);
    const int width = input.size(3);
    const int out_channels = weight.size(0);
    const int kernel_size = weight.size(2);

    // Calculate output dimensions (assuming stride=1, dilation=1)
    const int output_h = height - kernel_size + 2 * padding + 1;
    const int output_w = width - kernel_size + 2 * padding + 1;

    // Create output tensor
    auto output = torch::empty({batch_size, out_channels, output_h, output_w}, 
                              input.options());

    // Configure kernel launch
    const int total_elements = batch_size * out_channels * output_h * output_w;
    const int block_size = 256;
    const int grid_size = (total_elements + block_size - 1) / block_size;

    // Launch kernel
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "conv_bn_scale_kernel", ([&] {
        conv_bn_scale_kernel<scalar_t><<<grid_size, block_size>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
            running_mean.data_ptr<scalar_t>(),
            running_var.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            eps,
            scaling_factor,
            batch_size,
            in_channels,
            out_channels,
            height,
            width,
            kernel_size,
            output_h,
            output_w,
            padding
        );
    }));

    cudaDeviceSynchronize();
    return output;
}
"""

conv_bn_scale_cpp_source = """
torch::Tensor conv_bn_scale_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    torch::Tensor running_mean,
    torch::Tensor running_var,
    float eps,
    float scaling_factor,
    int padding
);
"""

# Compile the inline CUDA code
conv_bn_scale = load_inline(
    name="conv_bn_scale",
    cpp_sources=conv_bn_scale_cpp_source,
    cuda_sources=conv_bn_scale_source,
    functions=["conv_bn_scale_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=["-lcudart"],
)

class ModelNew(nn.Module):
    """
    Optimized model that fuses convolution, batch normalization, and scaling
    into a single custom CUDA kernel.
    """
    def __init__(self, in_channels, out_channels, kernel_size, scaling_factor):
        super(ModelNew, self).__init__()
        self.in_channels = in_channels
        self.out_channels = out_channels
        self.kernel_size = kernel_size
        self.scaling_factor = scaling_factor
        self.padding = 0  # Original model uses no padding

        # Initialize convolution parameters
        self.weight = nn.Parameter(torch.empty(out_channels, in_channels, kernel_size, kernel_size))
        self.bias = nn.Parameter(torch.empty(out_channels))

        # Initialize batch normalization parameters
        self.register_buffer('running_mean', torch.zeros(out_channels))
        self.register_buffer('running_var', torch.ones(out_channels))
        self.register_buffer('num_batches_tracked', torch.tensor(0, dtype=torch.long))

        # BN parameters
        self.eps = 1e-5
        self.momentum = 0.1

        # Initialize parameters
        self.reset_parameters()

        # Custom CUDA operator
        self.conv_bn_scale = conv_bn_scale

    def reset_parameters(self):
        # Initialize weights using Kaiming initialization
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in)
            nn.init.uniform_(self.bias, -bound, bound)

        # Initialize BN buffers
        self.running_mean.zero_()
        self.running_var.fill_(1)

    def forward(self, x):
        # During training, compute batch statistics
        if self.training:
            # First compute convolution output
            conv_output = torch.nn.functional.conv2d(
                x, 
                self.weight, 
                self.bias, 
                padding=self.padding
            )

            # Compute batch statistics
            batch_mean = conv_output.mean([0, 2, 3])
            batch_var = conv_output.var([0, 2, 3], unbiased=False)

            # Update running statistics
            n = self.num_batches_tracked.item()
            momentum = self.momentum
            if n > 0:
                momentum = min(momentum, 1.0 / (n + 1))

            with torch.no_grad():
                self.running_mean = (1 - momentum) * self.running_mean + momentum * batch_mean
                self.running_var = (1 - momentum) * self.running_var + momentum * batch_var
                self.num_batches_tracked.add_(1)

            # Apply BN and scaling using batch statistics during training
            inv_std = 1.0 / torch.sqrt(batch_var + self.eps)
            scale = self.scaling_factor * inv_std
            shift = -batch_mean * scale

            # Apply fused operation
            output = conv_output * scale.view(1, -1, 1, 1) + shift.view(1, -1, 1, 1)

            return output
        else:
            # Use fused kernel with running statistics for inference
            return self.conv_bn_scale.conv_bn_scale_cuda(
                x,
                self.weight,
                self.bias,
                self.running_mean,
                self.running_var,
                self.eps,
                self.scaling_factor,
                self.padding
            )

