    const scalar_t mean = running_mean[c];
    const scalar_t var = running_var[c];
    const scalar_t inv_std = 1.0 / sqrt(var + eps);
    result = (result - mean) * inv_std * scaling_factor;

    // Store result
    output[idx] = result;
